document.addEventListener('DOMContentLoaded',()=>{const loginForm=document.getElementById('loginForm'),loginCard=document.getElementById('loginCard'),profileCard=document.getElementById('profileCard'),displayName=document.getElementById('displayName'),loginMessage=document.getElementById('loginMessage'),logoutButton=document.getElementById('logoutButton'),logoutSection=document.getElementById('logoutSection'),themeToggle=document.getElementById('themeToggle'),navToggle=document.getElementById('navToggle'),navMenu=document.getElementById('navMenu'),pageNav=document.querySelector('.page-nav'),loginNavLink=document.querySelector('.nav-links a[href="#loginCard"]');function updateTheme(t){document.body.classList.toggle('dark-mode',t==='dark');document.body.classList.toggle('light-mode',t==='light');if(themeToggle){const l=t==='dark'?'Switch to light theme':'Switch to dark theme',i=t==='dark'?'dark_mode':'wb_sunny';themeToggle.setAttribute('aria-label',l);themeToggle.setAttribute('title',l);const icon=themeToggle.querySelector('.icon');if(icon)icon.textContent=i}localStorage.setItem('theme',t)}if(themeToggle)themeToggle.addEventListener('click',()=>{const n=document.body.classList.contains('dark-mode')?'light':'dark';updateTheme(n)});if(navToggle&&navMenu){navToggle.addEventListener('click',()=>{const open=navMenu.classList.toggle('open');navToggle.setAttribute('aria-expanded',open?'true':'false')});navMenu.querySelectorAll('a').forEach(link=>{link.addEventListener('click',()=>{navMenu.classList.remove('open');navToggle.setAttribute('aria-expanded','false')})});document.addEventListener('click',e=>{if(!navMenu.contains(e.target)&&!navToggle.contains(e.target)){navMenu.classList.remove('open');navToggle.setAttribute('aria-expanded','false')}})}updateTheme(localStorage.getItem('theme')||'dark');function showProfile(u){if(displayName)displayName.textContent=u;if(loginCard)loginCard.classList.add('hidden');if(profileCard)profileCard.classList.remove('hidden');if(logoutSection)logoutSection.classList.remove('hidden');if(logoutButton)logoutButton.classList.remove('hidden');if(loginMessage)loginMessage.textContent='';if(pageNav)pageNav.classList.remove('hidden');if(loginNavLink)loginNavLink.classList.add('hidden')}function showLogin(){if(loginCard)loginCard.classList.remove('hidden');if(profileCard)profileCard.classList.add('hidden');if(logoutSection)logoutSection.classList.add('hidden');if(logoutButton)logoutButton.classList.add('hidden');if(loginForm)loginForm.reset();if(loginMessage)loginMessage.textContent='';if(pageNav)pageNav.classList.add('hidden');if(loginNavLink)loginNavLink.classList.remove('hidden')}if(loginForm)loginForm.addEventListener('submit',e=>{e.preventDefault();const u=document.getElementById('username').value.trim(),p=document.getElementById('password').value.trim();if(!u||!p){if(loginMessage)loginMessage.textContent='Please enter a username and password.';return}showProfile(u)});if(logoutButton)logoutButton.addEventListener('click',()=>{showLogin()});const clickBadge=document.getElementById('clickBadge');if(clickBadge){let viewCount=Number(localStorage.getItem('viewCount')||0);viewCount+=1;localStorage.setItem('viewCount',viewCount);clickBadge.textContent=`Page views: ${viewCount}`}const sectionLinks=Array.from(document.querySelectorAll('.nav-links a')),sections=sectionLinks.map(l=>document.querySelector(l.getAttribute('href'))).filter(Boolean);if(sections.length){const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(!entry.target.id)return;const link=document.querySelector('.nav-links a[href="#'+entry.target.id+'"]');if(entry.isIntersecting){sectionLinks.forEach(a=>a.classList.remove('active'));if(link)link.classList.add('active')}})},{root:null,rootMargin:'0px 0px -40% 0px',threshold:.1});sections.forEach(s=>observer.observe(s));sectionLinks.forEach(a=>{a.addEventListener('click',()=>{sectionLinks.forEach(x=>x.classList.remove('active'));a.classList.add('active')})})}});